class Solution:
    def minimumSum(self, grid) -> int:
        R, C = len(grid), len(grid[0])
        INF = float('inf')
        def bbox(r1, r2, c1, c2):
            minr = minc = INF
            maxr = maxc = -INF
            for i in range(r1, r2+1):
                for j in range(c1, c2+1):
                    if grid[i][j]:
                        if i < minr: minr = i
                        if i > maxr: maxr = i
                        if j < minc: minc = j
                        if j > maxc: maxc = j
            if minr == INF: return 0
            return (maxr - minr + 1) * (maxc - minc + 1)
        best = INF
        for i in range(R - 2):
            for j in range(i + 1, R - 1):
                best = min(best, bbox(0,i,0,C-1) + bbox(i+1,j,0,C-1) + bbox(j+1,R-1,0,C-1))
        for i in range(C - 2):
            for j in range(i + 1, C - 1):
                best = min(best, bbox(0,R-1,0,i) + bbox(0,R-1,i+1,j) + bbox(0,R-1,j+1,C-1))
        for i in range(R - 1):
            for j in range(C - 1):
                best = min(best,
                    bbox(0,i,0,C-1) + bbox(i+1,R-1,0,j) + bbox(i+1,R-1,j+1,C-1),
                    bbox(0,i,0,j) + bbox(0,i,j+1,C-1) + bbox(i+1,R-1,0,C-1))
        return best

