var minimumSum = function(grid) {
    const R = grid.length, C = grid[0].length;
    function bbox(r1, r2, c1, c2) {
        let minR = Infinity, maxR = -Infinity, minC = Infinity, maxC = -Infinity;
        for (let i = r1; i <= r2; i++) {
            for (let j = c1; j <= c2; j++) {
                if (grid[i][j]) {
                    if (i < minR) minR = i;
                    if (i > maxR) maxR = i;
                    if (j < minC) minC = j;
                    if (j > maxC) maxC = j;
                }
            }
        }
        if (minR === Infinity) return 0;
        return (maxR - minR + 1) * (maxC - minC + 1);
    }
    let best = Infinity;
    for (let i = 0; i < R - 2; i++)
        for (let j = i + 1; j < R - 1; j++)
            best = Math.min(best, bbox(0,i,0,C-1) + bbox(i+1,j,0,C-1) + bbox(j+1,R-1,0,C-1));
    for (let i = 0; i < C - 2; i++)
        for (let j = i + 1; j < C - 1; j++)
            best = Math.min(best, bbox(0,R-1,0,i) + bbox(0,R-1,i+1,j) + bbox(0,R-1,j+1,C-1));
    for (let i = 0; i < R - 1; i++) {
        for (let j = 0; j < C - 1; j++) {
            best = Math.min(best,
                bbox(0,i,0,C-1) + bbox(i+1,R-1,0,j) + bbox(i+1,R-1,j+1,C-1),
                bbox(0,i,0,j) + bbox(0,i,j+1,C-1) + bbox(i+1,R-1,0,C-1));
        }
    }
    return best;
};
